//go:build ignore

package main

import (
	"bytes"
	"go/format"
	"log"
	"os"
	"text/template"
)

const tmplText = `
// Code generated by generate_server.go; DO NOT EDIT.

package rpcfunc
{{range $n0 := .}}{{$n := add1 $n0}}
type serverArgs{{$n}}[{{range $i := $n}}{{if $i}}, {{end}}A{{$i}}{{end}} any] struct {
{{- range $i := $n}}
	Arg{{$i}} A{{$i}}
{{- end}}
}

// RegisterFunc{{$n}} registers a {{$n}}-arg function with the server.
// It returns the function's ID for use in Caller(ID) expressions.
func RegisterFunc{{$n}}[{{range $i := $n}}{{if $i}}, {{end}}A{{$i}}{{end}}, R any](s *Server, f func({{range $i := $n}}{{if $i}}, {{end}}A{{$i}}{{end}}) (R, error)) int {
	return register(s,
		func(args serverArgs{{$n}}[{{range $i := $n}}{{if $i}}, {{end}}A{{$i}}{{end}}]) (R, error) {
			return f({{range $i := $n}}{{if $i}}, {{end}}args.Arg{{$i}}{{end}})
		},
	)
}
{{end}}
`

const maxArity = 10

func main() {
	funcTmpl := template.Must(template.New("funcs").Funcs(template.FuncMap{
		"add1": func(i int) int { return i + 1 },
	}).Parse(tmplText))

	var buf bytes.Buffer
	if err := funcTmpl.Execute(&buf, maxArity); err != nil {
		panic(err)
	}

	src, err := format.Source(buf.Bytes())
	if err != nil {
		os.Stderr.Write(buf.Bytes())
		log.Fatal(err)
	}
	if err := os.WriteFile("server_gen.go", src, 0o666); err != nil {
		log.Fatal(err)
	}
}
